import React, { useState } from 'react';
import { Button, Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { tscdService } from '../../../services/tscd/tscdService';
import type { DepreciationDto } from '../../../services/tscd/models';
import { MONTH_OPTIONS, yearOptions } from '../../../constants/voucher';
import { formatVnd } from '../../../utils/formatters';
import erp from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

const KhauHaoPage: React.FC = () => {
  const [reloadKey, setReloadKey] = useState(0);
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(String(now.getMonth() + 1));
  const [year, setYear] = useState(String(now.getFullYear()));
  const [data, setData] = useState<DepreciationDto | null>(null);
  const [loading, setLoading] = useState(false);
  const [running, setRunning] = useState(false);
  const [posting, setPosting] = useState(false);

  const load = () => {
    setLoading(true);
    tscdService.getDepreciation(Number(month), Number(year))
      .then(setData)
      .catch(err => dispatch(addToast({ message: err?.message ?? 'Lỗi tải khấu hao', type: 'error' })))
      .finally(() => setLoading(false));
  };
  const handleSearch = () => setReloadKey(k => k + 1);
  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) load(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [month, year]);

  const handleRun = async () => {
    setRunning(true);
    try {
      await tscdService.runDepreciation(Number(month), Number(year));
      dispatch(addToast({ message: 'Tính khấu hao thành công', type: 'success' }));
      load();
    } catch (e: unknown) {
      dispatch(addToast({ message: e instanceof Error ? e.message : 'Lỗi tính KH', type: 'error' }));
    } finally {
      setRunning(false);
    }
  };

  const handlePost = async () => {
    setPosting(true);
    try {
      await tscdService.postDepreciation(Number(month), Number(year));
      dispatch(addToast({ message: 'Ghi sổ khấu hao thành công', type: 'success' }));
      load();
    } catch (e: unknown) {
      dispatch(addToast({ message: e instanceof Error ? e.message : 'Lỗi ghi sổ KH', type: 'error' }));
    } finally {
      setPosting(false);
    }
  };

  return (
    <div className={erp.page}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}><h1 className={erp.title}><i className="fas fa-chart-line" /> Khấu hao TSCĐ</h1></div>
      </div>
      <div className={erp.filtersBar} data-testid={`erp-khau-hao-filters`}>
        <Select value={month} onChange={e => setMonth(e.target.value)} options={MONTH_OPTIONS} size="small" />
        <Select value={year} onChange={e => setYear(e.target.value)} options={yearOptions()} size="small" />
        <Button variant="primary" onClick={handleRun} loading={running}>Tính KH</Button>
        <Button variant="secondary" onClick={handlePost} loading={posting}>Ghi sổ</Button>
        <ListSearchRefreshButtons testIdPrefix="erp-khau-hao" onSearch={handleSearch} onRefresh={refresh} showSearch={false} />
      </div>
      <div className={erp.tableCard}>
        {loading ? <div className={erp.loading}>Đang tải...</div> : !data ? <div className={erp.empty}>Không có dữ liệu</div> : (
          <>
            <div className={erp.summaryBar}>
              <div className={erp.summaryItem}><label className={erp.label}>Trạng thái</label><strong>{data.status}</strong></div>
              <div className={erp.summaryItem}><label className={erp.label}>Tổng KH</label><strong>{formatVnd(data.totalAmount)}</strong></div>
            </div>
            <div className={erp.tableWrapper}>
              <table className={erp.table}>
                <thead><tr><th>Mã TS</th><th>Tên</th><th>TK</th><th className={erp.colRight}>Số tiền</th></tr></thead>
                <tbody>{data.lines.map((l, i) => (
                  <tr key={i}>
                    <td><code>{l.assetCode}</code></td>
                    <td>{l.assetName}</td>
                    <td><code>{l.accountCode}</code></td>
                    <td className={erp.colRight}>{formatVnd(l.amount)}</td>
                  </tr>
                ))}</tbody>
              </table>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default KhauHaoPage;
